Program 1
import java.util.Optional;

public class OptionalMap {

public static void main(String[] args) {

Optional<String> name =
Optional.of("Vijay");

Optional<String> upperCase =
name.map(String::toUpperCase);

System.out.println(upperCase);

}
}

Output

Optional[VIJAY]